#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <sys/time.h>
#include <cuda_runtime.h>

FILE *fp;

struct Node
{
    int starting;
    int no_of_edges;
};

static inline double omp_get_wtime_cuda()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (double)tv.tv_sec + (double)tv.tv_usec * 1.0e-6;
}

#define CUDA_CHECK(call)                                                        \
    do {                                                                        \
        cudaError_t err__ = (call);                                             \
        if (err__ != cudaSuccess) {                                             \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__,    \
                    cudaGetErrorString(err__));                                 \
            exit(EXIT_FAILURE);                                                 \
        }                                                                       \
    } while (0)

__global__ void bfs_kernel_phase1(
    int no_of_nodes,
    const Node *graph_nodes,
    const int *graph_edges,
    int *graph_mask,
    int *updating_graph_mask,
    const int *graph_visited,
    int *cost)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && graph_mask[tid] == 1) {
        graph_mask[tid] = 0;
        int edge_start = graph_nodes[tid].starting;
        int edge_end = edge_start + graph_nodes[tid].no_of_edges;
        int next_cost = cost[tid] + 1;

        for (int i = edge_start; i < edge_end; i++) {
            int id = graph_edges[i];
            if (graph_visited[id] == 0) {
                if (atomicCAS(&updating_graph_mask[id], 0, 1) == 0) {
                    cost[id] = next_cost;
                }
            }
        }
    }
}

__global__ void bfs_kernel_phase2(
    int no_of_nodes,
    int *graph_mask,
    int *updating_graph_mask,
    int *graph_visited,
    int *stop)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && updating_graph_mask[tid] == 1) {
        graph_mask[tid] = 1;
        graph_visited[tid] = 1;
        updating_graph_mask[tid] = 0;
        atomicExch(stop, 1);
    }
}

void Usage(int argc, char **argv)
{
    (void)argc;
    fprintf(stderr, "Usage: %s <num_threads> <input_file>\n", argv[0]);
}

void BFSGraph(int argc, char **argv)
{
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char *input_f;
    int num_omp_threads;

    if (argc != 3) {
        Usage(argc, argv);
        exit(0);
    }

    num_omp_threads = atoi(argv[1]);
    (void)num_omp_threads;
    input_f = argv[2];

    printf("Reading File\n");

    fp = fopen(input_f, "r");
    if (!fp) {
        printf("Error Reading graph file\n");
        return;
    }

    int source = 0;

    fscanf(fp, "%d", &no_of_nodes);

    Node *h_graph_nodes = (Node *)malloc(sizeof(Node) * no_of_nodes);
    int *h_graph_mask = (int *)malloc(sizeof(int) * no_of_nodes);
    int *h_updating_graph_mask = (int *)malloc(sizeof(int) * no_of_nodes);
    int *h_graph_visited = (int *)malloc(sizeof(int) * no_of_nodes);

    int start, edgeno;

    for (int i = 0; i < no_of_nodes; i++) {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = 0;
        h_updating_graph_mask[i] = 0;
        h_graph_visited[i] = 0;
    }

    fscanf(fp, "%d", &source);

    h_graph_mask[source] = 1;
    h_graph_visited[source] = 1;

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int *h_graph_edges = (int *)malloc(sizeof(int) * edge_list_size);
    for (int i = 0; i < edge_list_size; i++) {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if (fp)
        fclose(fp);

    int *h_cost = (int *)malloc(sizeof(int) * no_of_nodes);
    for (int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    printf("Start traversing the tree\n");

    Node *d_graph_nodes = NULL;
    int *d_graph_edges = NULL;
    int *d_graph_mask = NULL;
    int *d_updating_graph_mask = NULL;
    int *d_graph_visited = NULL;
    int *d_cost = NULL;
    int *d_stop = NULL;

    CUDA_CHECK(cudaMalloc((void **)&d_graph_nodes, sizeof(Node) * no_of_nodes));
    CUDA_CHECK(cudaMalloc((void **)&d_graph_edges, sizeof(int) * edge_list_size));
    CUDA_CHECK(cudaMalloc((void **)&d_graph_mask, sizeof(int) * no_of_nodes));
    CUDA_CHECK(cudaMalloc((void **)&d_updating_graph_mask, sizeof(int) * no_of_nodes));
    CUDA_CHECK(cudaMalloc((void **)&d_graph_visited, sizeof(int) * no_of_nodes));
    CUDA_CHECK(cudaMalloc((void **)&d_cost, sizeof(int) * no_of_nodes));
    CUDA_CHECK(cudaMalloc((void **)&d_stop, sizeof(int)));

    CUDA_CHECK(cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * no_of_nodes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * edge_list_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_cost, h_cost, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice));

    double start_time = omp_get_wtime_cuda();

    bool stop;
    int k = 0;
    const int threads_per_block = 256;
    const int blocks = (no_of_nodes + threads_per_block - 1) / threads_per_block;

    do {
        stop = false;
        CUDA_CHECK(cudaMemset(d_stop, 0, sizeof(int)));

        bfs_kernel_phase1<<<blocks, threads_per_block>>>(
            no_of_nodes,
            d_graph_nodes,
            d_graph_edges,
            d_graph_mask,
            d_updating_graph_mask,
            d_graph_visited,
            d_cost);
        CUDA_CHECK(cudaGetLastError());

        bfs_kernel_phase2<<<blocks, threads_per_block>>>(
            no_of_nodes,
            d_graph_mask,
            d_updating_graph_mask,
            d_graph_visited,
            d_stop);
        CUDA_CHECK(cudaGetLastError());

        int h_stop = 0;
        CUDA_CHECK(cudaMemcpy(&h_stop, d_stop, sizeof(int), cudaMemcpyDeviceToHost));
        stop = (h_stop != 0);
        k++;
    } while (stop);

    CUDA_CHECK(cudaMemcpy(h_cost, d_cost, sizeof(int) * no_of_nodes, cudaMemcpyDeviceToHost));

    double end_time = omp_get_wtime_cuda();
    printf("Compute time: %lf\n", (end_time - start_time));

    FILE *fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++)
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    fclose(fpo);
    printf("Result stored in result.txt\n");

    CUDA_CHECK(cudaFree(d_graph_nodes));
    CUDA_CHECK(cudaFree(d_graph_edges));
    CUDA_CHECK(cudaFree(d_graph_mask));
    CUDA_CHECK(cudaFree(d_updating_graph_mask));
    CUDA_CHECK(cudaFree(d_graph_visited));
    CUDA_CHECK(cudaFree(d_cost));
    CUDA_CHECK(cudaFree(d_stop));

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);
}

int main(int argc, char **argv)
{
    BFSGraph(argc, argv);
    return 0;
}
